# Module: shapes
# Contains: Interface and class hierarchy for shapes
from utils import Color, Point, GeometryUtils

# Interface for anything that can be drawn
interface IDrawable:
    def draw(self) -> str
        ...

# Interface for objects with area
interface IHasArea:
    def area(self) -> float
        ...

# Abstract base class for all shapes
@abstract
class Shape(IDrawable, IHasArea):
    _name: str
    _color: Color

    def __init__(self, name: str, color: Color):
        self._name = name
        self._color = color

    @virtual
    property get name(self) -> str:
        return self._name

    @virtual
    property get color(self) -> Color:
        return self._color

    @abstract
    def area(self) -> float
        ...

    @virtual
    def describe(self) -> str:
        return f"{self._name} with area {self.area()}"

# Concrete: Circle class
class Circle(Shape):
    _center: Point
    _radius: float

    def __init__(self, name: str, color: Color, center: Point, radius: float):
        super().__init__(name, color)
        self._center = center
        self._radius = radius

    @override
    def area(self) -> float:
        return GeometryUtils.circle_area(self._radius)

    @override
    def draw(self) -> str:
        return f"Drawing circle {self._name} at {self._center}"

# Concrete: Rectangle class
class Rectangle(Shape):
    _top_left: Point
    _width: float
    _height: float

    def __init__(self, name: str, color: Color, top_left: Point, width: float, height: float):
        super().__init__(name, color)
        self._top_left = top_left
        self._width = width
        self._height = height

    @override
    def area(self) -> float:
        return GeometryUtils.rectangle_area(self._width, self._height)

    @override
    def draw(self) -> str:
        return f"Drawing rectangle {self._name} at {self._top_left}"

    @override
    def describe(self) -> str:
        return f"Rectangle {self._name}: {self._width} x {self._height} = {self.area()}"

# Concrete: Triangle (using 3 points)
class Triangle(Shape):
    _p1: Point
    _p2: Point
    _p3: Point

    def __init__(self, name: str, color: Color, p1: Point, p2: Point, p3: Point):
        super().__init__(name, color)
        self._p1 = p1
        self._p2 = p2
        self._p3 = p3

    @override
    def area(self) -> float:
        # Using shoelace formula
        return abs(
            (self._p1.x * (self._p2.y - self._p3.y) +
             self._p2.x * (self._p3.y - self._p1.y) +
             self._p3.x * (self._p1.y - self._p2.y)) / 2.0
        )

    @override
    def draw(self) -> str:
        return f"Drawing triangle {self._name}"

