# Module: renderer
# Contains: Renderer that works with shapes
from shapes import Shape, Circle, Rectangle, Triangle, IDrawable, IHasArea
from utils import Color, Point

# Renderer class that uses shapes polymorphically
class SceneRenderer:
    _shapes: list[Shape]

    def __init__(self):
        self._shapes = []

    def add_shape(self, shape: Shape) -> None:
        self._shapes.append(shape)

    def render_all(self) -> list[str]:
        results: list[str] = []
        for shape in self._shapes:
            results.append(shape.draw())
        return results

    def total_area(self) -> float:
        total: float = 0.0
        for shape in self._shapes:
            total += shape.area()
        return total

    def count_by_color(self, color: Color) -> int:
        count: int = 0
        for shape in self._shapes:
            if shape.color == color:
                count += 1
        return count

# Factory classes with proper abstract method
@abstract
class ShapeFactory:
    @abstract
    def create_shape(self, name: str) -> Shape
        ...

class CircleFactory(ShapeFactory):
    @override
    def create_shape(self, name: str) -> Shape:
        return Circle(name, Color.BLUE, Point(0.0, 0.0), 5.0)

class RectangleFactory(ShapeFactory):
    @override
    def create_shape(self, name: str) -> Shape:
        return Rectangle(name, Color.GREEN, Point(0.0, 0.0), 10.0, 20.0)
